const cfg = $json;
const newsApiKey = ($env.NEWSAPI_KEY || '').trim();

const rssGoogle = (query) => `https://news.google.com/rss/search?q=${encodeURIComponent(query)}&hl=de&gl=DE&ceid=DE:de`;

const sources = [
  {
    sourceId: 'newsapi_world_de_focus',
    label: 'NewsAPI World',
    type: 'newsapi',
    requiresKey: true,
    topic: 'general',
    url: 'https://newsapi.org/v2/everything?q=(Weltpolitik%20OR%20Europa%20OR%20Deutschland)&language=de&sortBy=publishedAt&pageSize=25'
  },
  {
    sourceId: 'newsapi_politics_de_focus',
    label: 'NewsAPI Politik',
    type: 'newsapi',
    requiresKey: true,
    topic: 'politics',
    url: 'https://newsapi.org/v2/everything?q=(Politik%20OR%20Bundestag%20OR%20Bundesregierung)&language=de&sortBy=publishedAt&pageSize=25'
  },
  {
    sourceId: 'newsapi_tech_de_focus',
    label: 'NewsAPI Tech',
    type: 'newsapi',
    requiresKey: true,
    topic: 'tech',
    url: 'https://newsapi.org/v2/everything?q=(Technologie%20OR%20IT%20OR%20Digitalisierung)&language=de&sortBy=publishedAt&pageSize=25'
  },
  {
    sourceId: 'rss_google_ulm',
    label: 'Google News Ulm',
    type: 'rss',
    requiresKey: false,
    topic: 'regional',
    url: rssGoogle('Ulm OR Dornstadt')
  },
  {
    sourceId: 'rss_google_dornstadt',
    label: 'Google News Dornstadt',
    type: 'rss',
    requiresKey: false,
    topic: 'regional',
    url: rssGoogle('Dornstadt OR Ulm')
  },
  {
    sourceId: 'rss_tagesschau_de',
    label: 'Tagesschau',
    type: 'rss',
    requiresKey: false,
    topic: 'general',
    url: 'https://www.tagesschau.de/infoservices/alle-meldungen-100~rss2.xml'
  },
  {
    sourceId: 'rss_google_economy_de',
    label: 'Google News Wirtschaft',
    type: 'rss',
    requiresKey: false,
    topic: 'economy',
    url: rssGoogle('Wirtschaft OR Boerse OR Inflation Deutschland')
  },
  {
    sourceId: 'rss_google_traffic_ulm',
    label: 'Google News Verkehr',
    type: 'rss',
    requiresKey: false,
    topic: 'traffic',
    url: rssGoogle('Verkehr Ulm OR A8 OR B10 OR OePNV Ulm')
  },
  {
    sourceId: 'rss_google_warnings_bw',
    label: 'Google News Warnlagen',
    type: 'rss',
    requiresKey: false,
    topic: 'warnings',
    url: rssGoogle('Unwetter Baden-Wuerttemberg OR Polizeieinsatz Ulm OR Katastrophenschutz')
  },
  {
    sourceId: 'rss_google_energy_de',
    label: 'Google News Energie',
    type: 'rss',
    requiresKey: false,
    topic: 'energy',
    url: rssGoogle('Strompreis OR Gaspreis OR Energie Deutschland')
  },
  {
    sourceId: 'rss_google_ai_de',
    label: 'Google News KI',
    type: 'rss',
    requiresKey: false,
    topic: 'ai',
    url: rssGoogle('KI OR Automation OR AI Regulation Deutschland')
  }
];

const normalizeText = (value) => String(value || '')
  .replace(/<!\[CDATA\[(.*?)\]\]>/gs, '$1')
  .replace(/<[^>]*>/g, ' ')
  .replace(/&amp;/g, '&')
  .replace(/&quot;/g, '&quot;')
  .replace(/&lt;/g, '<')
  .replace(/&gt;/g, '>')
  .replace(/\s+/g, ' ')
  .trim();

const parseRss = (xml, source) => {
  const out = [];
  const itemRegex = /<item>([\s\S]*?)<\/item>/g;
  let match;
  while ((match = itemRegex.exec(xml)) !== null) {
    const block = match[1];
    const title = normalizeText((block.match(/<title>([\s\S]*?)<\/title>/i) || [])[1]);
    const link = normalizeText((block.match(/<link>([\s\S]*?)<\/link>/i) || [])[1]);
    const pubDateRaw = normalizeText((block.match(/<pubDate>([\s\S]*?)<\/pubDate>/i) || [])[1]);
    const publishedAt = pubDateRaw ? new Date(pubDateRaw).toISOString() : null;
    if (!title || !link) continue;
    out.push({
      title,
      url: link,
      source: source.label,
      sourceId: source.sourceId,
      publishedAt,
      topic: source.topic
    });
  }
  return out;
};

const parseNewsApi = (data, source) => {
  const articles = Array.isArray(data?.articles) ? data.articles : [];
  return articles
    .filter((a) => a && a.title && a.url)
    .map((a) => ({
      title: String(a.title).trim(),
      url: String(a.url).trim(),
      source: String(a?.source?.name || source.label).trim(),
      sourceId: source.sourceId,
      publishedAt: a.publishedAt || null,
      topic: source.topic
    }));
};

const fetchOne = async (source) => {
  if (source.requiresKey && !newsApiKey) {
    return {
      sourceId: source.sourceId,
      label: source.label,
      status: 'skipped_missing_key',
      requiresKey: true,
      count: 0,
      items: [],
      error: null
    };
  }

  try {
    const options = {
      method: 'GET',
      url: source.url,
      timeout: 20000
    };

    if (source.type === 'newsapi') {
      options.headers = { 'X-Api-Key': newsApiKey };
      options.json = true;
    }

    const raw = await this.helpers.httpRequest(options);
    const items = source.type === 'newsapi'
      ? parseNewsApi(raw, source)
      : parseRss(String(raw || ''), source);

    return {
      sourceId: source.sourceId,
      label: source.label,
      status: 'ok',
      requiresKey: source.requiresKey,
      count: items.length,
      items,
      error: null
    };
  } catch (error) {
    return {
      sourceId: source.sourceId,
      label: source.label,
      status: 'error',
      requiresKey: source.requiresKey,
      count: 0,
      items: [],
      error: String(error?.message || error || 'Unknown error')
    };
  }
};

const results = await Promise.all(sources.map((s) => fetchOne(s)));

return [{
  json: {
    config: cfg,
    sourceResults: results
  }
}];

const cfg = $json.config || {};
const sourceResults = Array.isArray($json.sourceResults) ? $json.sourceResults : [];

const toNumber = (v, fallback) => {
  const n = Number(v);
  return Number.isFinite(n) ? n : fallback;
};

const lookbackHours = Math.max(1, toNumber(cfg.lookbackHours, 24));
const maxChars = Math.max(300, toNumber(cfg.maxChars, 1300));
const now = Date.now();
const minTs = now - (lookbackHours * 60 * 60 * 1000);

const maxByTopic = {
  regional: Math.max(0, toNumber(cfg.maxRegional, 3)),
  politics: Math.max(0, toNumber(cfg.maxPolitics, 3)),
  tech: Math.max(0, toNumber(cfg.maxTech, 2)),
  economy: Math.max(0, toNumber(cfg.maxEconomy, 2)),
  traffic: Math.max(0, toNumber(cfg.maxTraffic, 1)),
  warnings: Math.max(0, toNumber(cfg.maxWarnings, 1)),
  energy: Math.max(0, toNumber(cfg.maxEnergy, 1)),
  ai: Math.max(0, toNumber(cfg.maxAi, 1))
};

const includeLinks = {
  headline: !!cfg.includeLinksHeadline,
  regional: !!cfg.includeLinksRegional,
  politics: !!cfg.includeLinksPolitics,
  tech: !!cfg.includeLinksTech,
  economy: !!cfg.includeLinksEconomy,
  traffic: !!cfg.includeLinksTraffic,
  warnings: !!cfg.includeLinksWarnings,
  energy: !!cfg.includeLinksEnergy,
  ai: !!cfg.includeLinksAi,
  general: !!cfg.includeLinksGeneral
};

let linksLeft = Math.max(0, toNumber(cfg.maxLinksTotal, 0));

const normalize = (s) => String(s || '').toLowerCase().replace(/https?:\/\/[^\s]+/g, '').replace(/[^a-z0-9aeiou\u00e4\u00f6\u00fc\u00df\s]/g, ' ').replace(/\s+/g, ' ').trim();

const topicOrder = ['regional', 'politics', 'tech', 'economy', 'traffic', 'warnings', 'energy', 'ai'];

const allItems = [];
for (const source of sourceResults) {
  const items = Array.isArray(source?.items) ? source.items : [];
  for (const item of items) {
    allItems.push(item);
  }
}

const unique = [];
const seen = new Set();
for (const item of allItems) {
  const url = String(item.url || '').trim();
  const title = String(item.title || '').trim();
  if (!url || !title) continue;
  const key = `${url}|${normalize(title)}`;
  if (seen.has(key)) continue;
  seen.add(key);
  unique.push(item);
}

const germanFocusRegex = /(deutschland|berlin|bundesregierung|bundestag|europa|eu|nrw|bayern|baden-wuerttemberg|baden-württemberg|ulm|dornstadt|hamburg|muenchen|münchen|frankfurt)/i;

const scored = unique
  .map((item) => {
    const publishedTs = item.publishedAt ? Date.parse(item.publishedAt) : NaN;
    const isFresh = Number.isFinite(publishedTs) ? publishedTs >= minTs : true;
    if (!isFresh) return null;

    const title = String(item.title || '');
    const source = String(item.source || 'Quelle');
    const topic = String(item.topic || 'general');

    let score = 0;
    if (Number.isFinite(publishedTs)) score += Math.max(0, 48 - ((now - publishedTs) / 3600000));
    if (germanFocusRegex.test(`${title} ${source}`)) score += 25;
    if (topic === 'regional') score += 20;
    if (topic === 'politics') score += 14;
    if (topic === 'tech') score += 10;

    return { ...item, topic, score, publishedTs: Number.isFinite(publishedTs) ? publishedTs : 0 };
  })
  .filter(Boolean)
  .sort((a, b) => (b.score - a.score) || (b.publishedTs - a.publishedTs));

const byTopic = {
  regional: [],
  politics: [],
  tech: [],
  economy: [],
  traffic: [],
  warnings: [],
  energy: [],
  ai: []
};

for (const item of scored) {
  if (byTopic[item.topic]) byTopic[item.topic].push(item);
}

const take = (arr, n) => arr.slice(0, Math.max(0, n));

const selected = {
  headline: scored[0] || null,
  regional: take(byTopic.regional, maxByTopic.regional),
  politics: take(byTopic.politics, maxByTopic.politics),
  tech: take(byTopic.tech, maxByTopic.tech),
  economy: take(byTopic.economy, maxByTopic.economy),
  traffic: take(byTopic.traffic, maxByTopic.traffic),
  warnings: take(byTopic.warnings, maxByTopic.warnings),
  energy: take(byTopic.energy, maxByTopic.energy),
  ai: take(byTopic.ai, maxByTopic.ai)
};

const formatItem = (item, withLink) => {
  const source = item.source ? ` - ${item.source}` : '';
  if (withLink && linksLeft > 0) {
    linksLeft -= 1;
    return `- ${item.title}${source}\n  ${item.url}`;
  }
  return `- ${item.title}${source}`;
};

const sections = [];

if (selected.headline) {
  sections.push({
    title: '🏆 Headline of the day',
    lines: [formatItem(selected.headline, includeLinks.headline)]
  });
}

const sectionConfig = [
  { key: 'regional', title: '📍 Regionales (Ulm, Dornstadt)' },
  { key: 'politics', title: '🏛️ Politik' },
  { key: 'tech', title: '💻 Tech' },
  { key: 'economy', title: '📈 Wirtschaft & Maerkte' },
  { key: 'traffic', title: '🚦 Verkehr & Infrastruktur' },
  { key: 'warnings', title: '⚠️ Warnlagen' },
  { key: 'energy', title: '⚡ Energie & Verbraucher' },
  { key: 'ai', title: '🤖 KI & Automation' }
];

for (const conf of sectionConfig) {
  const items = selected[conf.key] || [];
  if (!items.length) continue;
  const withLink = includeLinks[conf.key] && linksLeft > 0;
  sections.push({
    title: conf.title,
    lines: items.map((item) => formatItem(item, withLink))
  });
}

const blocks = [];
for (const sec of sections) {
  blocks.push(`${sec.title}\n${sec.lines.join('\n')}`);
}

let messageCore = blocks.join('\n\n').trim();

const configuredSources = sourceResults.length;
const usedSources = sourceResults.filter((s) => Number(s.count || 0) > 0).length;
const skipSources = sourceResults.filter((s) => s.status === 'skipped_missing_key').length;
const errorSources = sourceResults.filter((s) => s.status === 'error').length;
const irrelevantSources = sourceResults.filter((s) => s.status === 'ok' && Number(s.count || 0) === 0).length;

const footerParts = [];
if (skipSources > 0) footerParts.push(`Skip ${skipSources}`);
if (irrelevantSources > 0) footerParts.push(`Irrelevant ${irrelevantSources}`);
if (errorSources > 0) footerParts.push(`Fehler ${errorSources}`);

const footer = [`Quellen ${usedSources}/${configuredSources}`]
  .concat(footerParts.length ? [footerParts.join(' | ')] : [])
  .join('\n');

if (!messageCore) {
  messageCore = 'Heute keine relevanten News gefunden.';
}

let message = `${messageCore}\n\n${footer}`.trim();
if (message.length > maxChars) {
  const reserve = footer.length + 8;
  const allowedCore = Math.max(80, maxChars - reserve);
  const sliced = messageCore.slice(0, allowedCore).replace(/\s+[^\s]*$/, '').trim();
  message = `${sliced}...\n\n${footer}`;
}

const totalSelected = [
  selected.headline ? 1 : 0,
  ...topicOrder.map((k) => (selected[k] || []).length)
].reduce((acc, n) => acc + n, 0);

return [{
  json: {
    okToSend: totalSelected > 0,
    message,
    recipient: '',
    metrics: {
      configuredSources,
      usedSources,
      skipSources,
      irrelevantSources,
      errorSources,
      totalSelected
    },
    selected
  }
}];
